export class OpenAIImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = modelMaxImagesPerCall[this.modelId] ?? 1;

  get provider(): string { return this.config.provider; }

  constructor(
    readonly modelId: OpenAIImageModelId,
    private readonly config: OpenAIImageModelConfig,
  ) {}

  async doGenerate({
    prompt, files, mask, n, size, aspectRatio, seed,
    providerOptions, headers, abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]) {
    const warnings: Array<SharedV3Warning> = [];

    // Handle unsupported features
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details: 'This model does not support aspect ratio. Use `size` instead.',
      });
    }

    // Make API call via postFormDataToApi or postJsonToApi
    const { value: response, responseHeaders } = await postFormDataToApi({
      url: this.config.url({ path: '/images/edits', modelId: this.modelId }),
      headers: combineHeaders(this.config.headers(), headers),
      formData: convertToFormData<OpenAIImageEditInput>({
        model: this.modelId,
        prompt,
        image: await Promise.all(files.map(file => fileToBlob(file))),
        mask: mask != null ? await fileToBlob(mask) : undefined,
        n, size,
        ...(providerOptions.openai ?? {}),
      }),
      failedResponseHandler: openaiFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(openaiImageResponseSchema),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      usage: response.usage != null ? {
        inputTokens: response.usage.input_tokens ?? undefined,
        outputTokens: response.usage.output_tokens ?? undefined,
        totalTokens: response.usage.total_tokens ?? undefined,
      } : undefined,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
      providerMetadata: {
        openai: {
          images: response.data.map(item => ({
            revisedPrompt: item.revised_prompt,
          })),
        },
      },
    };
  }
}
```

**FAL** (`/packages/fal/src/fal-image-model.ts` - excerpt):
```typescript
export class FalImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  async doGenerate({
    prompt, n, size, aspectRatio, seed,
    providerOptions, files, mask, abortSignal, headers,
  }: Parameters<ImageModelV3['doGenerate']>[0]) {
    const warnings: Array<SharedV3Warning> = [];

    // Convert size/aspectRatio
    let imageSize: FalImageSize | undefined;
    if (size) {
      const [width, height] = size.split('x').map(Number);
      imageSize = { width, height };
    } else if (aspectRatio) {
      imageSize = convertAspectRatioToSize(aspectRatio);
    }

    // Parse provider options
    const falOptions = await parseProviderOptions({
      provider: 'fal',
      providerOptions,
      schema: falImageModelOptionsSchema,
    });

    // Build request body
    const requestBody: Record<string, unknown> = {
      prompt, seed, image_size: imageSize, num_images: n,
    };

    // Handle image editing with data URIs
    if (files != null && files.length > 0) {
      requestBody.image_url = convertImageModelFileToDataUri(files[0]);
    }

    if (mask != null) {
      requestBody.mask_url = convertImageModelFileToDataUri(mask);
    }

    // Make API call
    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/fal-ai/...`,
      headers: combineHeaders(...),
      body: requestBody,
      failedResponseHandler: createJsonErrorResponseHandler(...),
      successfulResponseHandler: createJsonResponseHandler(falImageResponseSchema),
      abortSignal,
      fetch: this.config.fetch,
    });

    return { images: [response.image.url], warnings, ... };
  }
}
```

