20	    baseURL: 'https://api.example.com',
21	    headers: headers ?? { 'api-key': 'test-key' },
22	    fetch,
23	    _internal: {
24	      currentDate,
25	    },
26	  });
27	}
28	
29	describe('FalImageModel', () => {
30	  const server = createTestServer({
31	    'https://api.example.com/fal-ai/qwen-image': {
32	      response: {
33	        type: 'json-value',
34	        body: {
35	          images: [
36	            {
37	              url: 'https://api.example.com/image.png',
