47	      response: {
48	        type: 'binary',
49	        body: Buffer.from('test-binary-content'),
50	      },
51	    },
52	  });
53	
54	  describe('doGenerate', () => {
55	    it('should pass the correct parameters including size', async () => {
56	      const model = createBasicModel();
57	
58	      await model.doGenerate({
59	        prompt,
60	        files: undefined,
61	        mask: undefined,
62	        n: 1,
63	        size: '1024x1024',
64	        aspectRatio: undefined,
65	        seed: 123,
66	        providerOptions: { fal: { additional_param: 'value' } },
67	      });
