import { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const TEST_BASE_URL = 'https://api.pixelart.ai/v1';
const TEST_MODEL_ID = 'pixelart-v1';
const TEST_ENDPOINT = `${TEST_BASE_URL}/images/generations`;

const prompt = 'A castle made of pixels';

const TEST_B64 = 'aGVsbG8='; // base64 for "hello"

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel(TEST_MODEL_ID, {
    provider: 'pixelart.image',
    url: ({ path }) => `${TEST_BASE_URL}${path}`,
    headers: headers ?? { Authorization: 'Bearer test-key' },
    fetch,
    _internal: {
      currentDate,
    },
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    [TEST_ENDPOINT]: {
      response: {
        type: 'json-value',
        body: {
          created: 1712345678,
          data: [{ b64_json: TEST_B64 }],
        },
      },
    },
  });

  describe('constructor', () => {
    it('should expose correct provider and model information', () => {
      const model = createBasicModel();

      expect(model.provider).toBe('pixelart.image');
      expect(model.modelId).toBe(TEST_MODEL_ID);
      expect(model.specificationVersion).toBe('v3');
      expect(model.maxImagesPerCall).toBe(4);
    });
  });

  describe('doGenerate', () => {
    it('should pass the correct basic parameters', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: TEST_MODEL_ID,
        prompt,
        n: 1,
        size: '512x512',
      });
    });

    it('should pass seed when provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: 42,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: TEST_MODEL_ID,
        prompt,
        n: 1,
        seed: 42,
      });
    });

    it('should pass style and pixelDensity from provider options', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 2,
        size: '256x256',
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {
          pixelart: {
            style: 'retro',
            pixelDensity: 32,
          },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: TEST_MODEL_ID,
        prompt,
        n: 2,
        size: '256x256',
        style: 'retro',
        pixel_density: 32,
      });
    });

    it('should omit style and pixelDensity when not provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).not.toHaveProperty('style');
      expect(body).not.toHaveProperty('pixel_density');
    });

    it('should warn for unsupported aspectRatio', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: '16:9',
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(result.warnings).toHaveLength(1);
      expect(result.warnings[0]).toMatchObject({
        type: 'unsupported',
        feature: 'aspectRatio',
      });
    });

    it('should warn for unsupported files (image editing)', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: [
          {
            type: 'url',
            url: 'https://example.com/image.png',
          },
        ],
        mask: undefined,
        providerOptions: {},
      });

      expect(result.warnings).toHaveLength(1);
      expect(result.warnings[0]).toMatchObject({
        type: 'unsupported',
        feature: 'image',
        details: 'PixelArt does not support image editing.',
      });
    });

    it('should warn for unsupported mask (inpainting)', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: {
          type: 'url',
          url: 'https://example.com/mask.png',
        },
        providerOptions: {},
      });

      expect(result.warnings).toHaveLength(1);
      expect(result.warnings[0]).toMatchObject({
        type: 'unsupported',
        feature: 'image',
        details: 'PixelArt does not support inpainting.',
      });
    });

    it('should emit multiple warnings for multiple unsupported features', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: '1:1',
        seed: undefined,
        files: [{ type: 'url', url: 'https://example.com/img.png' }],
        mask: { type: 'url', url: 'https://example.com/mask.png' },
        providerOptions: {},
      });

      expect(result.warnings).toHaveLength(3);
    });

    it('should return images as base64 strings', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(result.images).toHaveLength(1);
      expect(result.images[0]).toBe(TEST_B64);
    });

    it('should return multiple images when n > 1', async () => {
      server.urls[TEST_ENDPOINT].response = {
        type: 'json-value',
        body: {
          created: 1712345678,
          data: [{ b64_json: TEST_B64 }, { b64_json: TEST_B64 }],
        },
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 2,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(result.images).toHaveLength(2);
      expect(result.images[0]).toBe(TEST_B64);
      expect(result.images[1]).toBe(TEST_B64);
    });

    it('should pass headers', async () => {
      const modelWithHeaders = createBasicModel({
        headers: {
          'Custom-Provider-Header': 'provider-header-value',
        },
      });

      await modelWithHeaders.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
        headers: {
          'Custom-Request-Header': 'request-header-value',
        },
      });

      expect(server.calls[0].requestHeaders).toMatchObject({
        'custom-provider-header': 'provider-header-value',
        'custom-request-header': 'request-header-value',
      });
    });

    it('should include timestamp, modelId and headers in response', async () => {
      const testDate = new Date('2024-01-01T00:00:00Z');
      const model = createBasicModel({
        currentDate: () => testDate,
      });

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(result.response).toStrictEqual({
        timestamp: testDate,
        modelId: TEST_MODEL_ID,
        headers: expect.any(Object),
      });
    });

    it('should handle API errors', async () => {
      server.urls[TEST_ENDPOINT].response = {
        type: 'error',
        status: 400,
        body: JSON.stringify({
          error: {
            message: 'Invalid prompt: prompt cannot be empty',
            type: 'invalid_request_error',
          },
        }),
      };

      const model = createBasicModel();

      await expect(
        model.doGenerate({
          prompt,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          files: undefined,
          mask: undefined,
          providerOptions: {},
        }),
      ).rejects.toMatchObject({
        message: 'Invalid prompt: prompt cannot be empty',
        statusCode: 400,
        url: TEST_ENDPOINT,
      });
    });

    it('should produce no warnings when all supported options are used', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: '1024x1024',
        aspectRatio: undefined,
        seed: 99,
        files: undefined,
        mask: undefined,
        providerOptions: {
          pixelart: {
            style: '8bit',
            pixelDensity: 64,
          },
        },
      });

      expect(result.warnings).toHaveLength(0);
    });
  });
});

